#!/usr/bin/env node
/**
 * Update the coverage badge in README.md from c8 json-summary output.
 *
 * Reads:  coverage/coverage-summary.json (generated by c8 --reporter=json-summary)
 * Writes: README.md (patches the shields.io badge URL in place)
 *
 * Usage:  node tools/update-coverage-badge.js
 * Called automatically by tools/release.js after tests pass.
 */

import { readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');

const summaryPath = join(root, 'coverage', 'coverage-summary.json');
const readmePath = join(root, 'README.md');

// Read coverage summary
let summary;
try {
  summary = JSON.parse(readFileSync(summaryPath, 'utf8'));
} catch (e) {
  console.error('  Could not read coverage/coverage-summary.json -- run npm test first');
  process.exit(1);
}

const pct = summary.total.statements.pct;
const rounded = Math.floor(pct * 10) / 10; // e.g. 97.3

// Choose badge color based on coverage level
var color;
if (rounded >= 95) color = 'brightgreen';
else if (rounded >= 90) color = 'green';
else if (rounded >= 80) color = 'yellowgreen';
else if (rounded >= 70) color = 'yellow';
else color = 'red';

// Build the badge URL (shields.io static badge)
const badgeUrl = `https://img.shields.io/badge/coverage-${rounded}%25-${color}.svg`;

// Replace in README
let readme = readFileSync(readmePath, 'utf8');
const badgeRe = /\[!\[Coverage\]\(https:\/\/img\.shields\.io\/badge\/coverage-[^)]+\)\]/;

if (!badgeRe.test(readme)) {
  console.error('  Could not find coverage badge in README.md');
  process.exit(1);
}

const newBadge = `[![Coverage](${badgeUrl})]`;
readme = readme.replace(badgeRe, newBadge);
writeFileSync(readmePath, readme);

console.log(`  Coverage: ${rounded}% (${color})`);
console.log(`  Badge updated in README.md`);
